@Slf4j
public class EgovSecurityMap {

	Map<String, String> map = new HashMap<>();

	public String get(String key) {
		return map.get(key);
	}

	public void put(String key, String value) {
		String value2 = value;

		// 특정 암호화된 파라미터 복호화 처리
		switch (key) {
		case "proxyId":
		case "serverId":
		case "noteId":
		case "noteTrnsmitId":
		case "noteRecptnId":
		case "reprtId":
			log.debug("### EgovSecurityMap {} : {}", key, value);
			value2 = EgovComUtlController.decryptId(value);
			break;

		default:
			break;
		}

		map.put(key, value2);
	}

	@Override
	public String toString() {
		return map.toString();
	}

}

